import React from "react";
import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";
import SpeakableText from "../components/SpeakableText";

function getEmergencyLabel(lang) {
  if (lang === "ta") return "அவசரம்";
  if (lang === "hi") return "आपातकाल";
  if (lang === "ml") return "അപത്കാലം";
  return "Emergency";
}

function getHintText(lang) {
  if (lang === "ta") {
    return "ஒரு பெரிய பொத்தானைத் தட்டுங்கள். குரல் கட்டளைக்கு Speak பொத்தானைப் பயன்படுத்துங்கள்.";
  }
  if (lang === "hi") {
    return "एक बड़े बटन को दबाएं। वॉइस कमांड देने के लिए Speak बटन का उपयोग करें।";
  }
  if (lang === "ml") {
    return "ഒരു വലിയ ബട്ടൺ അമർത്തുക. വോയ്സ് കമാൻഡുകൾക്ക് Speak ബട്ടൺ ഉപയോഗിക്കുക.";
  }
  return "Tap one big button. Use the Speak button to give voice commands.";
}

export default function PatientHome() {
  const user = JSON.parse(sessionStorage.getItem("userData"));
  const { t, i18n } = useTranslation();
  const navigate = useNavigate();
  const lang = String(i18n.language || "en").toLowerCase();

  const quickActions = [
    { icon: "A", label: t("nav.appointments"), route: "/appointments" },
    { icon: "D", label: t("doctor"), route: "/consult" },
    { icon: "M", label: t("pharmacy"), route: "/pharmacy" },
    { icon: "E", label: getEmergencyLabel(lang), route: "/consult" },
    { icon: "S", label: t("nav.symptoms"), route: "/symptoms" }
  ];

  return (
    <div style={page}>
      <SpeakableText
        as="h2"
        text={`${t("welcome")}, ${user?.name || t("patient")}`}
        style={title}
        wrapperStyle={{ display: "flex", marginBottom: 6 }}
      />
      <SpeakableText
        as="p"
        text={getHintText(lang)}
        style={hint}
        wrapperStyle={{ display: "flex", marginBottom: 20 }}
      />

      <div style={actionGrid}>
        {quickActions.map((item) => (
          <div key={item.label} style={actionCard}>
            <button
              type="button"
              onClick={() => navigate(item.route)}
              style={actionButton}
              aria-label={item.label}
            >
              <span style={actionIcon} aria-hidden="true">
                {item.icon}
              </span>
              <span style={actionLabel}>{item.label}</span>
            </button>
            <SpeakableText text={item.label} />
          </div>
        ))}
      </div>
    </div>
  );
}

const page = {
  padding: 18,
  minHeight: "100vh",
  background:
    "radial-gradient(circle at top left, #dff7f3 0%, #e6f7ff 42%, #eef2ff 100%)"
};

const title = {
  color: "#0f2027",
  marginBottom: 6,
  fontSize: 34
};

const hint = {
  marginTop: 0,
  marginBottom: 20,
  fontSize: 20,
  color: "#164e63",
  fontWeight: 600
};

const actionGrid = {
  display: "grid",
  gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))",
  gap: 14
};

const actionCard = {
  display: "flex",
  flexDirection: "column",
  alignItems: "flex-start",
  gap: 8
};

const actionButton = {
  color: "#1b1b1b",
  border: "1px solid #d3dde2",
  borderRadius: 22,
  minHeight: 170,
  width: "100%",
  background: "#ffffff",
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
  justifyContent: "center",
  gap: 10,
  boxShadow: "0 8px 14px rgba(0,0,0,0.1)",
  cursor: "pointer",
  padding: 16
};

const actionIcon = {
  width: 62,
  height: 62,
  borderRadius: 999,
  border: "2px solid #9bb2bf",
  display: "grid",
  placeItems: "center",
  fontSize: 28,
  fontWeight: 700,
  lineHeight: 1
};

const actionLabel = {
  fontSize: 24,
  fontWeight: 800,
  letterSpacing: 0.3,
  textAlign: "center"
};
