import { useEffect, useMemo, useState } from "react";
import { useSearchParams } from "react-router-dom";
import { useTranslation } from "react-i18next";
import { addChatMessageCloud, getChatMessagesCloud } from "../services/cloudData";
import { hasSupabase } from "../supabaseClient";
import SpeakableText from "../components/SpeakableText";

export default function Chat() {
  const { t } = useTranslation();
  const [searchParams] = useSearchParams();
  const appointmentId = searchParams.get("appointmentId") || "";
  const role = sessionStorage.getItem("role") || "patient";
  const user = useMemo(() => {
    try {
      return JSON.parse(sessionStorage.getItem("userData")) || {};
    } catch {
      return {};
    }
  }, []);

  const [messages, setMessages] = useState([]);
  const [text, setText] = useState("");
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const shouldUseCloud = hasSupabase && isOnline;

  useEffect(() => {
    const onOnline = () => setIsOnline(true);
    const onOffline = () => setIsOnline(false);
    window.addEventListener("online", onOnline);
    window.addEventListener("offline", onOffline);
    return () => {
      window.removeEventListener("online", onOnline);
      window.removeEventListener("offline", onOffline);
    };
  }, []);

  useEffect(() => {
    if (!appointmentId) return undefined;
    let active = true;

    async function loadMessages() {
      if (!shouldUseCloud) {
        setMessages([]);
        return;
      }
      const data = await getChatMessagesCloud(appointmentId);
      if (!active) return;
      setMessages(data);
    }

    loadMessages();
    const timer = setInterval(loadMessages, 1000);
    return () => {
      active = false;
      clearInterval(timer);
    };
  }, [appointmentId, shouldUseCloud]);

  async function sendMessage(e) {
    e.preventDefault();
    if (!appointmentId || !text.trim()) return;

    try {
      if (!shouldUseCloud) {
        alert(t("appointments_cloud_required_online"));
        return;
      }
      const payload = {
        text: text.trim(),
        senderRole: role,
        senderName: user?.name || (role === "doctor" ? t("doctor") : t("patient"))
      };
      await addChatMessageCloud(appointmentId, payload);

      const refreshed = await getChatMessagesCloud(appointmentId);
      setMessages(refreshed);
      setText("");
    } catch {
      alert(t("chat_unable_send"));
    }
  }

  if (!appointmentId) {
    return (
      <div style={styles.page}>
        <SpeakableText
          as="h2"
          text={t("chat_title")}
          style={styles.title}
          wrapperStyle={{ display: "flex" }}
        />
        <SpeakableText
          as="p"
          text={t("chat_invalid_consultation")}
          wrapperStyle={{ display: "flex" }}
        />
      </div>
    );
  }

  return (
    <div style={styles.page}>
      <SpeakableText
        as="h2"
        text={t("chat_title")}
        style={styles.title}
        wrapperStyle={{ display: "flex" }}
      />
      {!shouldUseCloud && (
        <SpeakableText
          as="p"
          text={t("chat_cloud_required")}
          style={styles.empty}
          wrapperStyle={{ display: "flex" }}
        />
      )}
      <div style={styles.chatBox}>
        {messages.length === 0 && (
          <SpeakableText
            as="p"
            text={t("chat_no_messages")}
            style={styles.empty}
            wrapperStyle={{ display: "flex" }}
          />
        )}
        {messages.map((m) => {
          const mine = m.senderRole === role;
          return (
            <div key={m.id} style={{ ...styles.msg, ...(mine ? styles.mine : styles.theirs) }}>
              <div style={styles.meta}>
                {m.senderName} ({m.senderRole})
              </div>
              <SpeakableText text={m.text} />
            </div>
          );
        })}
      </div>

      <form onSubmit={sendMessage} style={styles.form}>
        <input
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder={t("chat_type_message")}
          style={styles.input}
        />
        <button style={styles.button} type="submit">
          {t("chat_send")}
        </button>
      </form>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    background: "#e0f7fa",
    padding: 24
  },
  title: {
    marginTop: 0,
    color: "#0f2027"
  },
  chatBox: {
    background: "#fff",
    borderRadius: 12,
    padding: 12,
    minHeight: 320,
    boxShadow: "0 6px 16px rgba(0,0,0,0.12)"
  },
  empty: {
    color: "#5b7480"
  },
  msg: {
    maxWidth: "75%",
    borderRadius: 10,
    padding: "8px 10px",
    marginBottom: 8
  },
  mine: {
    marginLeft: "auto",
    background: "#2c5364",
    color: "#fff"
  },
  theirs: {
    marginRight: "auto",
    background: "#edf4f7",
    color: "#0d2430"
  },
  meta: {
    fontSize: 12,
    opacity: 0.85,
    marginBottom: 2
  },
  form: {
    marginTop: 12,
    display: "flex",
    gap: 8
  },
  input: {
    flex: 1,
    border: "1px solid #b8cfd8",
    borderRadius: 8,
    padding: "10px 12px"
  },
  button: {
    border: "none",
    borderRadius: 8,
    padding: "10px 14px",
    background: "#203a43",
    color: "#fff",
    cursor: "pointer"
  }
};
